import{T as a}from"./chunks/theme.DUCXC5Zm.js";import{o,c as t,af as r,E as d}from"./chunks/framework.5D6DWnkB.js";const p=JSON.parse('{"title":"PVE 与 NAS 数据中心折腾日记","description":"","frontmatter":{"title":"PVE 与 NAS 数据中心折腾日记","date":"2026-03-29T00:00:00.000Z"},"headers":[],"relativePath":"hardware/pve-samba.md","filePath":"hardware/pve-samba.md"}'),l={name:"hardware/pve-samba.md"},h=Object.assign(l,{setup(s){return(i,e)=>(o(),t("div",null,[e[0]||(e[0]=r('<h1 id="pve-与-nas-数据中心折腾日记" tabindex="-1">PVE 与 NAS 数据中心折腾日记 <a class="header-anchor" href="#pve-与-nas-数据中心折腾日记" aria-label="Permalink to &quot;PVE 与 NAS 数据中心折腾日记&quot;">​</a></h1><p>本文记录了我将主控机硬盘转移到 PVE 宿主机上，通过 Samba 进行网络共享的心路历程和避坑指南。</p><h2 id="需求" tabindex="-1">需求 <a class="header-anchor" href="#需求" aria-label="Permalink to &quot;需求&quot;">​</a></h2><p>把主控机（Windows 10）里面那些旧的、杂七杂八的机械硬盘拔出来，统统挂到 PVE 宿主机上，作为 NAS 数据中心。局域网内的设备全靠网络调取这些文件，方便管理和去重。</p><h2 id="方案选型" tabindex="-1">方案选型 <a class="header-anchor" href="#方案选型" aria-label="Permalink to &quot;方案选型&quot;">​</a></h2><p>当时有考虑过专门装个 TrueNAS 虚拟机，但经过评估：</p><ol><li><strong>内存不够吃</strong>（ZFS 非常吃内存）。</li><li><strong>直通硬盘步骤多</strong>且容易掉盘。</li></ol><p>最终决定：<strong>最朴素的 Samba</strong> 不搞虚拟机，直接在 PVE 宿主机（底层 Debian）底层把 USB 硬盘盒挂载上，跑 Samba 共享服务。</p><h2 id="硬盘格式化与挂载步骤" tabindex="-1">硬盘格式化与挂载步骤 <a class="header-anchor" href="#硬盘格式化与挂载步骤" aria-label="Permalink to &quot;硬盘格式化与挂载步骤&quot;">​</a></h2><ol><li><strong>查硬盘</strong>: <code>lsblk</code> 命令确认新插入硬盘的 <code>/dev/sdX</code> 盘符</li><li><strong>清理分区</strong>: <code>fdisk</code> 或 <code>parted</code> 清空所有 Windows 残留的分区。</li><li><strong>格式化</strong>: <code>mkfs.ext4 /dev/sdX1</code>。</li><li><strong>挂载</strong>: 写入 <code>/etc/fstab</code> 实现开机自动挂载到 <code>/mnt/data/</code>，并确保每次重启后都能自动挂载。</li></ol><h2 id="pve-数据与虚拟机备份策略-重要" tabindex="-1">PVE 数据与虚拟机备份策略 (重要) <a class="header-anchor" href="#pve-数据与虚拟机备份策略-重要" aria-label="Permalink to &quot;PVE 数据与虚拟机备份策略 (重要)&quot;">​</a></h2><p>一旦成了数据中心，备份必须提上日程。目前 PVE 上搭载了 Ubuntu (跑博客)、旁路由 OpenClash。</p><ol><li><p><strong>虚拟机全量备份 (VZDump)</strong>: 利用 PVE 自带的 <code>vzdump</code> 命令或通过 Web 面板，将所有虚拟机的全量镜像保存到 <code>/mnt/data/dump</code> 下，采用 <code>zstd</code> 高效压缩。 我配置了 <code>/etc/pve/vzdump.cron</code>，每周全自动跑一次全量备份。</p></li><li><p><strong>PVE 宿主机环境备份（防翻车）</strong>: 千万别全盘备份 PVE 系统！如果坏了，用 U 盘重装只需要 3 分钟。 真正要备份的是<strong>核心配置项</strong>，只要把以下三个目录打包备份好，重装系统后直接覆盖就能起死回生：</p><ul><li><code>/etc/pve/</code> （所有的虚拟机配置文件、硬盘分配清单）</li><li><code>/etc/network/interfaces</code> （网桥和旁路由相关的网络配置）</li><li><code>/etc/fstab</code> （你的 NAS 数据盘挂载记录）</li></ul></li></ol>',13)),d(a)]))}});export{p as __pageData,h as default};
